userDefinedLinkHintCss:
/* Vimium hint container */
.vimiumHintMarker {
  background: #1d1e21 !important;      /* accent */
  border: 1px solid #c3c3c3 !important; /* highlight */
  border-radius: 14px !important;
  padding: 3px 6px !important;

  box-shadow:
    0 0 0 1px rgba(101,144,253,0.35),
    0 6px 14px rgba(0,0,0,0.55) !important;
}

/* Hint text */
.vimiumHintMarker span {
  color: #d3d9e3 !important;           /* foreground */
  font-family: ui-monospace, monospace !important;
  font-size: 13px !important;
  font-weight: 600 !important;
}
